var e=[{id:`L4_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`생각보다 걸리적 거리는 놈들이 많은걸.`,JPN:`思ったより邪魔なやつらが多いな。`,ENG:`There are a lot more disruptors than I expected.`,TWN:`礙事的傢伙比預料中多啊。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`과연 초고심도의 이면세계...... 무저갱이라 할 만하군.`,JPN:`さすが超高深度の裏世界……底なしの地獄と呼ばれるのも無理はない。`,ENG:`No wonder they call the Counterside hyperdepths the bottomless pit.`,TWN:`果然超深度的異界……就是個無底洞。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`하지만 네놈들에게 낭비할 시간은 없다.`,JPN:`しかしお前たちに構っている暇はない。`,ENG:`But I have no time to waste on you.`,TWN:`我沒時間浪費在你們這些傢伙身上。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`단숨에 분쇄해 주마.`,JPN:`一気に粉砕してやる。`,ENG:`I'll crush you at once.`,TWN:`讓我一口氣粉碎你們吧！`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_UI_RECRUITMNET_LIGHTNING`},{id:`L9_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`......음?`,JPN:`……うむ？`,ENG:`Huh?`,TWN:`……嗯？`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`뭐지? 부서진 부위가 다시 회복되고 있군.`,JPN:`なんだ？　壊れた部位が再び回復している。`,ENG:`What's this? The damage is healing.`,TWN:`怎麼可能？粉碎的部位正在重新恢復。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`설마 재생 타입의 침식체인가? 귀찮은 놈들인데.`,JPN:`もしや再生タイプの侵食体か？　厄介な奴らに遭遇したな。`,ENG:`Are they the type that regenerates? How annoying.`,TWN:`難道是再生類型的侵蝕體嗎？真是些麻煩的敵人。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`아니, 조금 달라.`,JPN:`いや、違う。`,ENG:`No, not exactly.`,TWN:`不，有些不同。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`조직의 내구도도, 안정성도 평범한 재생 타입의 침식체들 보다 훨씬 뛰어나다.`,JPN:`組織の耐久度も安定性も、平凡な再生タイプの侵食体よりもはるかに優れている。`,ENG:`The tissue durability and stability of these C.O.s is far superior to that of normal regenerative C.O.s.`,TWN:`身體組織的耐久度和穩定性比普通再生類型的侵蝕體更出色。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`이건...... 마치 제이나의 능력과 비슷하군.`,JPN:`これは……まるでジェイナの能力に似ている。`,ENG:`This is... like Jaina's ability.`,TWN:`這個……好像跟婕娜的能力類似。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`놈들이 오는 곳은...... 네임리스 원의 침식파가 감지되는 방향인가?`,JPN:`奴らが来る方角は……ネームレスワンの侵食波が感知された方向か？`,ENG:`They're coming from... where the Nameless One's Corruption ray was detected.`,TWN:`這些傢伙出現的地方……是監測到無名1侵蝕波的方向嗎？`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`......불길하군, 서둘러야겠어.`,JPN:`……嫌な予感がする、急がねば。`,ENG:`That's ominous... I should hurry.`,TWN:`……我有不好的預感，看來要加快速度了。`},stage:{bg:`COUNTERSIDE_SPACE`,bgm:`THEMA_DIVE_EATER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};